"""
mkt-christ layer — Jude chapter 1 (verses 1–24; v25 already present)
Output: data/commentary/mkt-christ/jude.json
Run: python3 scripts/zc-christ-jude-1-1-full.py

Pre-existing: ch1v25 — merge_comm will skip it.

Interpretation decisions:
- v5 'the Lord' (some MSS read 'Jesus'): even with 'Lord,' the acting agent in Exodus
  judgment is the pre-existent Christ per 1 Cor 10:4 (the rock was Christ). The
  Christological identification is structurally necessary for Jude's argument.
- v14 Enoch's 'Lord coming with ten thousands' = Christ's parousia, applying the YHWH
  oracle of 1 Enoch 1:9 to the returning Christ (1 Thess 3:13).
- v24 'him who is able to keep you from stumbling... present you blameless' = God through
  Christ; Christ is the agent of preservation and the one before whose glory all are
  presented at the parousia.
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {
  "1": {
    "1": "<p>Jude identifies himself as 'servant of Jesus Christ and brother of James' — the self-designation 'servant of Jesus Christ' (<em>doulos Iēsou Christou</em>) is Paul's own formula (Phil 1:1; Titus 1:1; Rom 1:1) and represents Christological humility: Jude, who was a physical brother of Jesus (Matt 13:55; Mark 6:3 list Judas/Jude among the Lord's brothers), introduces himself not by his blood-relationship to Jesus but by his servant-relationship. The Christological community is addressed as 'called, loved in God the Father, and kept for Jesus Christ' (<em>tētērēmenois Iēsou Christō</em>): their preservation is Christological — they are being kept <em>for</em> Christ's return, held in trust until the day of his appearing.</p>",
    "2": "<p>'Mercy, peace, and love be multiplied to you' — the triad of eschatological gifts. Mercy reappears in v21 as 'the mercy of our Lord Jesus Christ' that believers wait for at the parousia; peace is the Christological peace achieved at the cross (Col 1:20); love is the love that God demonstrated in Christ (Rom 5:8: God demonstrates his love in that while we were still sinners Christ died for us). Jude prays that these gifts — already given in Christ — multiply toward the community as they contend against those who are denying the Lord who gave them.</p>",
    "3": "<p>'Contend for the faith once for all delivered to the saints' — the 'faith' (<em>pistis</em>) is the Christological gospel. 'Once for all delivered' (<em>hapax paradotheisē</em>) is the once-for-all language of Christ's unrepeatable sacrifice (Heb 9:28: Christ was offered once to bear the sins of many; 10:10: we have been sanctified through the offering of the body of Jesus Christ once for all). Just as Christ's atoning act is unrepeatable and complete, the apostolic faith-deposit that proclaims it is unrepeatable — it cannot be supplemented, revised, or replaced. The contention Jude urges is not for Jude's authority but for the Christ whose person and work the faith declares.</p>",
    "4": "<p>'Certain people... have denied our only Master and Lord, Jesus Christ' — the heresy that Jude opposes is explicitly Christological in its center: denial of Jesus Christ as 'only Master and Lord' (<em>ton monon despotēn kai kyrion hēmōn Iēsoun Christon</em>). The double title — absolute sovereign (<em>despotēs</em>) and confessed lord (<em>kyrios</em>) — frames the entire letter: the false teachers' ungodly conduct is the outward expression of their denial of Christ's absolute authority. Their condemnation was 'written beforehand' in Scripture — the typological patterns of judgment (vv. 5-7) are pre-written verdicts applied to those who deny Christ.</p>",
    "5": "<p>'The Lord, having saved the people out of Egypt, afterward destroyed those who did not believe' — the same Lord who redeemed is the Lord who judges. Some manuscripts read 'Jesus' (<em>Iēsous</em>) instead of 'Lord' (<em>kyrios</em>), which would explicitly identify the Exodus redeemer with the pre-existent Christ (as in 1 Cor 10:4: the rock that followed them was Christ; 1 Cor 10:9: we must not put Christ to the test, as some of them did). Even without this variant, Jude's application of the Lord's Exodus-judgment to present apostates presupposes the same Christological identification: the one who judged unbelief in the wilderness is the same Lord Jesus who will judge it at the parousia.</p>",
    "6": "<p>'The angels who did not stay within their own position of authority but left their proper dwelling' — the imprisoned Watchers of 1 Enoch (6-19; cf. Gen 6:1-4), bound in eternal chains awaiting the great Day of judgment. The Christological frame: these cosmic powers await judgment by the one before whom all things are subject (1 Pet 3:22: angels, authorities, and powers subjected to him; Col 2:15: disarmed the rulers and authorities). The bound angels' situation is the eschatological guarantee that Christ's authority over the cosmic order is real and his judgment-day judgment will execute what the cross already accomplished.</p>",
    "7": "<p>'Sodom and Gomorrah and the surrounding cities served as an example by undergoing the punishment of eternal fire' — the OT judgment-events are <em>typoi</em> (types, examples) of the eschatological judgment that Christ will execute at his return. Christ himself cited Sodom in eschatological contexts (Matt 10:15; 11:24: it will be more tolerable on the day of judgment for Sodom than for you; Luke 17:29: on the day Lot left Sodom, fire and sulfur rained from heaven). The 'eternal fire' is the same fire Christ warned of in his eschatological discourse (Matt 25:41: depart into the eternal fire prepared for the devil and his angels).</p>",
    "8": "<p>'These people also, relying on their dreams, defile the flesh, reject authority, and blaspheme the glorious ones' — the threefold Christological rejection: defiling the flesh (rejecting the incarnate Christ's demand for bodily holiness), rejecting authority (<em>kyriota</em>, the lordship — Christ's lordship in particular, denied in v4), and blaspheming the glorious ones (<em>doxas</em>, the angels through whom God's authority is mediated, or possibly the glorified Christ himself). The false teachers' conduct is not incidentally immoral but structurally anti-Christological: every offense flows from the central denial of Christ's lordship.</p>",
    "9": "<p>'But when the archangel Michael, contending with the devil, was disputing about the body of Moses, he did not presume to pronounce a blasphemous judgment but said, 'The Lord rebuke you'' — the contrast: even the highest angelic being deferred to the Lord's authority in matters of cosmic judgment. The 'Lord rebuke you' (<em>epitimēsai soi kyrios</em>, from Zech 3:2) identifies the Lord as the one who holds ultimate authority in cosmic disputes. Applied Christologically: the risen and exalted Christ (1 Pet 3:22: who has gone into heaven and is at the right hand of God, with angels, authorities, and powers subject to him) is the one to whom even Michael deferred. The false teachers who blaspheme without hesitation show more presumption than the archangel.</p>",
    "10": "<p>'But these people blaspheme all that they do not understand, and they are destroyed by all that they, like irrational animals, understand by instinct' — the Christological epistemological contrast: true understanding of spiritual realities comes through the Spirit of Christ (1 Cor 2:14: the natural person does not accept the things of the Spirit of God, for they are folly to him; 2:16: we have the mind of Christ). Those who lack the Spirit (v19) and operate by instinct alone are without the interpretive framework that Christ and his Spirit provide; they are blind to what they are blaspheming because they have rejected the one who gives sight (John 9:39: for judgment I came into this world... that those who do not see may see).</p>",
    "11": "<p>'Woe to them! They walked in the way of Cain and abandoned themselves for the sake of gain to Balaam's error and perished in Korah's rebellion' — three OT prototypes of anti-Christological rebellion: Cain, who rejected God's way and murdered the righteous brother (1 John 3:12: Cain murdered his brother; Christ is the righteous one prefigured in Abel, Heb 12:24: the sprinkled blood that speaks a better word than Abel's blood); Balaam, who led Israel into idolatry for profit (the same pattern as false teachers who exploit the community for gain); Korah, who usurped the legitimate high-priestly authority (Num 16) — the prototype of those who deny Christ's unique high-priestly mediation (Heb 7:24: he holds his priesthood permanently because he continues forever).</p>",
    "12": "<p>'Blemishes on your love feasts, fearlessly feasting with you, shepherds feeding themselves; waterless clouds, swept along by winds; fruitless trees in late autumn, twice dead, uprooted' — the pastoral images are Christological in their negative form. True shepherds model Christ the Good Shepherd who feeds the flock rather than himself (John 10:11-12; Ezek 34:2-4: shepherds who feed themselves). Fruitless trees contrast with the vine-and-branches image: Christ is the true vine, and those who abide in him bear fruit (John 15:2, 5: whoever abides in me and I in him bears much fruit). 'Twice dead' — dead in sin and in apostasy — contrasts with the double resurrection-life that Christ brings: physical and spiritual.</p>",
    "13": "<p>'Wild waves of the sea, casting up the foam of their own shame; wandering stars, for whom the gloom of utter darkness has been reserved forever' — the stars-of-darkness imagery has Christological contrast: Christ is the 'bright morning star' (Rev 22:16), the fixed star that gives reliable light; those who wander from him are the 'wandering stars' (<em>planētai asteres</em>, the root of 'planet') with no fixed reference. Daniel's eschatological promise — 'those who lead many to righteousness like the stars forever' (Dan 12:3) — describes the faithful teachers; the false teachers who lead away from righteousness inherit the gloom of darkness that is the anti-parousia: not light but eternal darkness.</p>",
    "14": "<p>'Enoch, the seventh from Adam, also prophesied about these, saying, 'See, the Lord is coming with ten thousands of his holy ones'' — the first NT citation of 1 Enoch (1:9), applied Christologically: the 'Lord' of Enoch's oracle (originally YHWH) is Christ at his parousia. The application follows the NT Christological pattern of identifying YHWH-coming texts with Christ's return (1 Thess 3:13: the coming of our Lord Jesus with all his holy ones; Matt 25:31: the Son of Man comes in his glory, and all the angels with him). Jude identifies Christ as the Lord of Enoch's cosmic judgment — the pre-existent Christ who is the subject of even pre-Mosaic prophecy.</p>",
    "15": "<p>'To execute judgment on all and to convict all the ungodly of all their deeds of ungodliness' — the universal eschatological judgment that Christ will execute (John 5:22: the Father has given all judgment to the Son; 5:27: the Father has given him authority to execute judgment because he is the Son of Man). The 'convicting' (<em>elegxai</em>) is the work of the Paraclete now (John 16:8: he will convict the world concerning sin, righteousness, and judgment) and of the returning Christ at the parousia. Jude's citation of Enoch functions to show that the judgment Christ will execute is not a new development but the culmination of a judgment-trajectory written from before the flood.</p>",
    "16": "<p>'These are grumblers, malcontents, following their own sinful desires; they are loud-mouthed boasters, showing favoritism to gain advantage' — the Christological diagnosis: Israel's grumbling against Moses in the wilderness was grumbling against God (Exod 16:8; 1 Cor 10:10); the false teachers who grumble against the apostolic leadership are grumbling against Christ who sent them (Matt 10:40: whoever receives you receives me, and whoever receives me receives him who sent me). The boasting is the anti-Christ boasting that Paul opposes (Gal 6:14: far be it from me to boast except in the cross of our Lord Jesus Christ); the Christ-cross pattern eliminates all other ground for boasting.</p>",
    "17": "<p>'But you must remember, beloved, the predictions of the apostles of our Lord Jesus Christ' — the apostles' predictions are extensions of Christ's own prophetic warnings (Matt 24:11: many false prophets will arise and lead many astray; 24:24: false christs and false prophets; Mark 13:22). The apostles spoke 'of our Lord Jesus Christ' — in his name and under his authority (1 Pet 1:12: things that even angels long to look into, that the Holy Spirit sent from heaven reported through those who proclaimed the gospel). To remember the apostolic teaching is to remember Christ's own teaching as transmitted through authorized witnesses.</p>",
    "18": "<p>'They said to you, 'In the last time there will be scoffers, following their own ungodly passions'' — the 'last time' (<em>ep' eschatou tou chronou</em>) has been inaugurated by Christ's first coming (1 Pet 1:20: he was foreknown before the foundation of the world but revealed in the last times; 1 Cor 10:11: the end of the ages has come). The scoffers of 2 Pet 3:3 ask 'where is the promise of his coming?' — they deny the parousia of Christ. In Jude, the scoffers deny his lordship (v4). Both forms of denial are anti-Christological and both were predicted; the fulfillment of the apostolic prediction confirms the Christological framework within which the community is operating.</p>",
    "19": "<p>'It is these who cause divisions, worldly people, devoid of the Spirit' — the Christological test: 'devoid of the Spirit' (<em>pneuma mē echontes</em>) is to be without the Spirit of Christ (Rom 8:9: if anyone does not have the Spirit of Christ, he is not his). Those who are devoid of Christ's Spirit cause divisions in the body of Christ (1 Cor 12:12-13: by one Spirit we were all baptized into one body); their divisiveness is the sociological expression of their Christological emptiness. The contrast with v20 — 'praying in the Holy Spirit' — frames the Spirit-possession as the distinguishing mark of authentic Christ-belonging.</p>",
    "20": "<p>'But you, beloved, building yourselves up in your most holy faith and praying in the Holy Spirit' — the Christological construction: the 'most holy faith' is the Christological gospel (v3: the faith once for all delivered); building up in it is building on the foundation of Christ (1 Cor 3:11: no other foundation can be laid than that which is Jesus Christ). Praying 'in the Holy Spirit' is praying in the Spirit of Christ who himself intercedes (Rom 8:26-27; 34: Christ Jesus is at the right hand of God and is also interceding for us). The community's prayer participates in Christ's own ongoing intercession.</p>",
    "21": "<p>'Keep yourselves in the love of God, waiting for the mercy of our Lord Jesus Christ that leads to eternal life' — the eschatological horizon is Christ's return. The 'mercy of our Lord Jesus Christ' (<em>to eleos tou kyriou hēmōn Iēsou Christou</em>) is the mercy he will show at his parousia — the final mercy of presenting the community blameless (v24) and granting eternal life. 'Eternal life' is Christ's own gift (John 17:2-3: you have given him authority over all flesh, to give eternal life to all whom you have given him; and this is eternal life, that they know you the only true God and Jesus Christ whom you have sent). The community perseveres by keeping its face turned toward Christ's coming.</p>",
    "22": "<p>'Have mercy on those who doubt' — the pastoral application of v21's mercy-of-Christ: the community is to extend toward doubting members the same mercy that Christ will extend at the parousia. The Christological ground: Christ himself was gentle with the doubting (Matt 11:28: come to me, all who are weary and heavy laden; John 20:27: to Thomas — put your finger here and see my hands). The mercy that the community extends to doubters is a Christological act — a making-present of Christ's own compassion for those whose faith is struggling.</p>",
    "23": "<p>'Save others by snatching them from the fire; to others show mercy with fear, hating even the garment stained by the flesh' — the rescue language echoes Amos 4:11 (a brand plucked from the burning) and Zech 3:2 (a brand plucked from the fire — applied to Joshua the high priest being rescued for priestly service). The snatching from fire is the community's participation in Christ's own rescue mission (Luke 19:10: the Son of Man came to seek and to save the lost); they act as agents of the one who himself was 'snatched from the fire' of death and Hades at the resurrection and who now snatches others through those he has commissioned. The 'fear' maintained while showing mercy is fear of Christ the coming judge (v15).</p>",
    "24": "<p>'Now to him who is able to keep you from stumbling and to present you blameless before the presence of his glory with great joy' — the doxology addresses God acting through Christ. The 'keeping from stumbling' (<em>phulaxai aptaistous</em>) is Christ's own intercessory work: he prays that none of those the Father has given him will be lost (John 17:12: I kept them in your name... none of them has been lost). The 'presentation blameless before his glory' is the parousia event: Christ presenting the community before himself (Col 1:22: to present you holy and blameless before him; Eph 5:27: that he might present the church to himself in splendor, without spot or wrinkle). Christ is simultaneously the one before whose glory they are presented and the agent who presents them.</p>"
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-christ', 'jude')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-christ', 'jude', existing)
    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / 'jude.json'))
    all_ok = True
    for ch in ['1']:
        missing = set(il.get(ch, {}).keys()) - set(existing.get(ch, {}).keys())
        if missing:
            print(f'  ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch {ch}: complete ({len(existing.get(ch, {}))} verses)')
    if all_ok:
        print('All verses present')
